xf:group.script:
/**
 * //property handling
 * $w.log("id:" + options.id);
 * $w.log("style:" + options.style);
 * $w.log("class:" + options.class);
 * $w.log("ref:" + options.ref);
 *
 * //event trigger
*/
// 초기 수행함수 
this.initAllBasin = function() {
	// fill 설정
	var selector = "#" + this.getID();
	var selectorSuffix = " .map-basin";
	// 한강
	document.querySelectorAll(selector + " .map-basin-h" + selectorSuffix).forEach(elm => elm.classList.add("map-basin-h-fill"));
	// 금강
	document.querySelectorAll(selector + " .map-basin-g" + selectorSuffix).forEach(elm => elm.classList.add("map-basin-g-fill"));
	// 낙동강
	document.querySelectorAll(selector + " .map-basin-n" + selectorSuffix).forEach(elm => elm.classList.add("map-basin-n-fill"));
	// 영섬강
	document.querySelectorAll(selector + " .map-basin-y" + selectorSuffix).forEach(elm => elm.classList.add("map-basin-y-fill"));
	// 제주
	document.querySelectorAll(selector + " .map-basin-jeju" + selectorSuffix).forEach(elm => elm.classList.add("map-jeju-fill"));
	// 울릉
	document.querySelectorAll(selector + " .map-basin-ulleung" + selectorSuffix).forEach(elm => elm.classList.add("map-ulleung-fill"));
};

// 초기 실행함수 수행
this.initAllBasin();

xf:group.xf:group:
.map-all-basin .map-basin {
	stroke: #888888;
	stroke-miterlimit: 1;
	stroke-width: 1;
}

.map-all-basin g[class*="map-basin-"]:not(.basin-hover):not(.basin-clone) {
	transform: scale(1.0);
	transition: all 0.4s ease 0s;
}

@supports (filter: drop-shadow(0.25rem 0.25rem 0.25rem #888888)) {
	.map-all-basin .basin-hover {
		transform: scale(1.02) rotateX(2deg) rotateY(2deg);
		transform-origin: unset;
		cursor: pointer;
		filter: drop-shadow(0.25rem 0.25rem 0.25rem #888888);
	}

	.map-all-basin .basin-clone {
		transform: scale(1.02);
		opacity: 0.7;
		transform-origin: unset;
		cursor: pointer;
	}
}

@supports not (filter: drop-shadow(0.25rem 0.25rem 0.25rem #888888)) {
	.map-all-basin .basin-hover {
		cursor: pointer;
	}

	.map-all-basin .basin-clone {
		cursor: pointer;
	}

	.map-all-basin .basin-clone .map-basin,
	.map-all-basin .basin-hover .map-basin {
		stroke: #888888;
		stroke-miterlimit: 2;
		stroke-width: 2;
	}
}

.map-basin-h-fill {
	fill: #F6FFED;
}

.map-basin-g-fill {
	fill: #FEF6ED;
}

.map-basin-n-fill {
	fill: #EEF6FF;
}

.map-basin-y-fill {
	fill: #FDEDFF;
}

.map-jeju-fill {
	fill: #EFEDFF;
}

.map-ulleung-fill {
	fill: #ECFFFF;
}
